class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        def is_semi_palindrome(substring):
            n = len(substring)
            for d in range(1, n):
                if n % d == 0:
                    groups = [[] for _ in range(d)]
                    for i in range(n):
                        groups[i % d].append(substring[i])
                    if all(self.is_palindrome(group) for group in groups):
                        return True
            return False

        def is_palindrome(s):
            return s == s[::-1]

        def min_changes_to_semi_palindrome(substring):
            n = len(substring)
            min_changes = float('inf')
            for d in range(1, n):
                if n % d == 0:
                    groups = [[] for _ in range(d)]
                    for i in range(n):
                        groups[i % d].append(substring[i])
                    changes = 0
                    for group in groups:
                        if not self.is_palindrome(group):
                            changes += sum(1 for i in range(len(group) // 2) if group[i] != group[-i - 1])
                    min_changes = min(min_changes, changes)
            return min_changes

        memo = {}
        def dp(i, k):
            if (i, k) in memo:
                return memo[(i, k)]
            if k == 0:
                return float('inf')
            if i == len(s):
                return 0
            min_changes = float('inf')
            for j in range(i + 1, len(s) + 1):
                substring = s[i:j]
                changes = min_changes_to_semi_palindrome(substring)
                min_changes = min(min_changes, changes + dp(j, k - 1))
            memo[(i, k)] = min_changes
            return min_changes

        return dp(0, k)
